def common_keys(left, right):
    result = {}
    for key, value in left.items():
        if key in right and right[key] == value:
            result[key] = value
    return result

def split_on_value(items, separator):
    result = []
    current = []
    for item in items:
        if item == separator:
            result.append(current)
            current = []
        else:
            current.append(item)
    result.append(current)
    return result

def longest_word(words):
    longest = words[0]
    for word in words[1:]:
        if len(word) > len(longest):
            longest = word
    return longest

def flatten_once(items):
    result = []
    for item in items:
        if isinstance(item, list):
            result.extend(item)
        else:
            result.append(item)
    return result

def count_by_length(words):
    result = {}
    for word in words:
        length = len(word)
        result[length] = result.get(length, 0) + 1
    return result

